<?php
namespace App\Http\Controllers;use App\Models\PaymentTransaction;use App\Models\TopupOrder;use App\Services\OrderService;use App\Services\RazorpayService;use App\Services\WalletService;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Str;class PaymentController extends Controller{public function walletOrder(Request $request,RazorpayService $razorpay){$data=$request->validate(['amount'=>'required|numeric|min:1|max:100000']);$minor=(int)round($data['amount']*100);$tx=PaymentTransaction::create(['tx_no'=>'TX'.date('YmdHis').strtoupper(Str::random(4)),'user_id'=>Auth::id(),'purpose'=>'wallet_topup','gateway'=>'razorpay','status'=>'created','amount_minor'=>$minor,'currency_code'=>'INR']);$order=$razorpay->createOrder($minor,$tx->tx_no,'INR');$tx->update(['gateway_order_id'=>$order['id'],'gateway_response'=>$order]);return view('payments.razorpay',['tx'=>$tx,'key'=>env('RAZORPAY_KEY','rzp_test_demo'),'callback'=>route('payment.verify')]);}public function directOrder(Request $request,RazorpayService $razorpay){$orderId=$request->validate(['order_id'=>'required|exists:topup_orders,id'])['order_id'];$order=TopupOrder::where('user_id',Auth::id())->findOrFail($orderId);$tx=PaymentTransaction::create(['tx_no'=>'TX'.date('YmdHis').strtoupper(Str::random(4)),'user_id'=>Auth::id(),'payable_type'=>TopupOrder::class,'payable_id'=>$order->id,'purpose'=>'topup_order','gateway'=>'razorpay','status'=>'created','amount_minor'=>$order->amount_minor,'currency_code'=>$order->currency_code]);$rzp=$razorpay->createOrder($tx->amount_minor,$tx->tx_no,$tx->currency_code);$tx->update(['gateway_order_id'=>$rzp['id'],'gateway_response'=>$rzp]);return view('payments.razorpay',['tx'=>$tx,'key'=>env('RAZORPAY_KEY','rzp_test_demo'),'callback'=>route('payment.verify')]);}public function verify(Request $request,RazorpayService $razorpay,WalletService $wallet,OrderService $orders){$data=$request->validate(['razorpay_order_id'=>'required','razorpay_payment_id'=>'required','razorpay_signature'=>'nullable']);$tx=PaymentTransaction::where('gateway_order_id',$data['razorpay_order_id'])->firstOrFail();if(!$razorpay->verifySignature($data['razorpay_order_id'],$data['razorpay_payment_id'],$data['razorpay_signature']??'demo')){$tx->update(['status'=>'failed']);return redirect('/')->with('error','Payment verification failed.');}if($tx->status!=='paid'){$tx->update(['status'=>'paid','gateway_payment_id'=>$data['razorpay_payment_id'],'gateway_signature'=>$data['razorpay_signature']??null,'gateway_response'=>$data]);if($tx->purpose==='wallet_topup'){$wallet->credit($tx->user_id,$tx->amount_minor,'Wallet recharge via Razorpay','payment_transaction',(string)$tx->id);return redirect()->route('wallet.index')->with('success','Wallet recharge successful.');}if($tx->purpose==='topup_order'){$order=TopupOrder::find($tx->payable_id);$order->update(['payment_mode'=>'online','payment_status'=>'paid','order_status'=>'processing','message'=>'Payment successful. Processing order.']);$orders->processProvider($order);return redirect()->route('orders.index')->with('success','Payment successful and order processed.');}}return redirect('/')->with('success','Payment already processed.');}}
